scwin.f_postDtChk = async function(odrNo, sellSeq, kcomcd, seaAirCls, blNo, mhno) {
    var params = {
        sysCd   : sysCd || "ilCommonEBC",
        queryId : "retrievePostDt",
        param1  : odrNo,
        param2  : sellSeq,
        param3  : kcomcd,
        param4  : seaAirCls,
        param5  : blNo,
        param6  : mhno,
        param7  :"",
        param8  : "",
        param9  : "",
        param10  : "",
        param11  : "",
        param12  : "",
        param13  : "",
        param14  : ""
    };

	ds_postDtDataSet.removeAll();
	dma_combo.setJSON(params);
    await $c.sbm.execute(sbm_popup);

	return ds_postDtDataSet;
};

scwin.f_validate = function () {
    // VALIDATE
    if (!$c.gus.cfValidate([ed_mhcurdt, ed_mheta, gr_buying, gr_partner])) {  // validExp 가 yes일때 check
        return false;
    }

    if (ed_mhcur.getValue() == "") {
        $c.gus.cfAlertMsg(ilcommon.E_MSG_CM_ERR_002, ["Currency"]); // @는 필수입력항목입니다.
        ed_mhcur.focus();
        return false;
    }

    if (ed_mheta.getValue() == "") {
        $c.gus.cfAlertMsg(ilcommon.E_MSG_CM_ERR_002, ["ETA"]); // @는 필수입력항목입니다.
