                return false;
            }
        }
    } 

    return true;
};

// 공통팝업 열기
scwin.f_PopUp = function (disGubun, chgGubun) {
    var rtnList = new Array();
    var pCode = "";
    var pName = "";
    switch (disGubun) {		
        case "Partner":
            pCode = ed_mhscd.getValue().trim();
            pName = ed_mhsnm.getValue().trim();

            ed_mhscd.setValue("");
            ed_mhsnm.setValue("");

            udc_ilcomCode.setSelectId("retrieveEngClntInfo");
            udc_ilcomCode.ilCommonPopUp(
                                            scwin.udc_Partner_callBackFunc,    		                                    // XML상의 SELECT ID	                                                   
                                            pCode,                                                                      // 화면에서의 ??? Code Element의	Value                                  
                                            pName,                                                                      // 화면에서의 ??? Name Element의	Value                                  
                                            chgGubun,                                                                   // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                                            '10',                                                                       // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                            'Partner Code,Partner Name,Address1,Address2,Address3,Address4,Tel,,,CRN',  // Title순서	                                                           
                                            '140,300,100,100,100,100,100,,,100',                                        // 보여주는 각 컬럼들의 폭	                                               
                                            '8,9',                                                                      // 컬럼중에서 숨기는	컬럼 지정	                                       
                                            null,                                                                       // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                                            '500',                                                                      // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
