// 화면이동
scwin.f_openPgm = function (name) {
    var openParam = {};
    if (name=="Partner") { 
        openParam = {
            kcomcd : scwin.hd_kcomcd || "",                                   // kcomcd
            seaair : "S",                                                     // sea:S, air:A
            iogb   : scwin.hd_mhio ,                                          // out:O, in:I
            blno   : "",                                                      // house blno
            mblno  : cnd_ed_mhmblno.getValue(),                               // master blno
            mhno   : cnd_lc_mhno.getValue()                                   // mhno
        };        

        var strPath = "/ui/il/acc/acpar/ac_104_01_01b.xml";
        $c.win.openMenu("Partner Invoice", strPath, "ac_104_01_01b.xml", openParam);
    } else if (name=="Profit") {
        openParam = {
            kcomcd : scwin.hd_kcomcd || "",                                   // kcomcd
            seaair : "S",                                                     // sea:S, air:A
            iogb   : scwin.hd_mhio ,                                          // out:O, in:I
            blno   : cnd_ed_hhblno.getValue(),                                // house blno
            mblno  : "",                                                      // master blno
            mhno   : cnd_lc_mhno.getValue()                                   // mhno
        };      

        var strPath = "/ui/il/pfm/pfbs/pe_101_01_01b.xml";
        $c.win.openMenu("Booking Sheet", strPath, "pe_101_01_01b.xml", openParam);
    } else if (name=="paymentINV") {
        openParam = {
            kcomcd : scwin.hd_kcomcd || "",                                   // kcomcd
            seaair : "S",                                                     // sea:S, air:A
            iogb   : scwin.hd_mhio ,                                          // out:O, in:I
            blno   : "",                                                      // house blno
            mblno  : cnd_ed_mhmblno.getValue(),                               // master blno
            mhno   : cnd_lc_mhno.getValue()                                   // mhno
        };      

        var strPath = "/ui/il/acc/acpay/ac_106_01_01b.xml";
        $c.win.openMenu("Payment Invoice", strPath, "ac_106_01_01b.xml", openParam);
    } else if (name=="MasterBLFind") {
        openParam = {
            mhio   : scwin.hd_mhio 
        };      

        var strPath = "/ui/il/seaout/sobl/se_106_01_02b.xml";
        $c.win.openMenu("Master B/L Search", strPath, "se_106_01_02b.xml", openParam);
    } else if (name=="MasterBLHeader") {
        openParam = { 
            linkcheck : "3", 
            kcomcd : scwin.hd_kcomcd || "",                                   // kcomcd
            blno   : cnd_ed_hhblno.getValue(),                                // house blno
            mhno   : cnd_lc_mhno.getValue()                                   // mhno
        };      

        var strPath = "/ui/il/seainb/sibl/se_202_01_01b.xml";
        $c.win.openMenu("Import Master B/L", strPath, "se_202_01_01b.xml", openParam);
    }
};

// MHNO 가져오기  cool7
scwin.f_MhnoLoading = async function () {
    var strClntNo = "";
    strClntNo = cnd_ed_hhblno.getValue().trim() ;

    if (strClntNo.length > 0) {
        scwin._comboTarget = "HMHNO1";
